<section class="admin-page-head"><div><p class="eyebrow">ATELIER</p><h1>Articole</h1></div><div class="button-row"><a class="admin-button secondary" href="<?= e(url('/admin/atelier/calendar')) ?>">Calendar editorial</a><a class="admin-button" href="<?= e(url('/admin/atelier/creare')) ?>">Articol nou</a></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><section class="admin-panel"><form class="admin-filters" method="get"><input type="search" name="q" value="<?= e($q) ?>" placeholder="Titlu sau slug"><select name="status"><option value="">Toate statusurile</option><?php foreach(['draft','in_review','scheduled','published','archived'] as $value): ?><option <?= $status===$value?'selected':'' ?>><?= e($value) ?></option><?php endforeach; ?></select><button class="admin-button" type="submit">Filtrează</button><a href="<?= e(url('/admin/atelier/taxonomii')) ?>">Taxonomii</a></form><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Articol</th><th>Autor</th><th>Status</th><th>Publicare</th><th>Revizii</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><a href="<?= e(url('/admin/atelier/'.$item['id'].'/edit')) ?>"><strong><?= e($item['title']) ?></strong></a><small>/atelier/<?= e($item['slug']) ?></small></td><td><?= e($item['author_name']?:'—') ?></td><td><span class="status-pill <?= $item['status']==='published'?'success':'' ?>"><?= e($item['status']) ?></span></td><td><?= $item['scheduled_at']?date('d.m.Y H:i',strtotime($item['scheduled_at'])):($item['published_at']?date('d.m.Y',strtotime($item['published_at'])):'—') ?></td><td><a href="<?= e(url('/admin/atelier/'.$item['id'].'/revisions')) ?>"><?= (int)$item['revision_count'] ?></a></td></tr><?php endforeach; ?></tbody></table></div></section>
